fn main() {
    let a = 10;
    let b = 0;

    let result = a / b;

    println!("Result: {}");
}

fixed_code:
fn main() {
    let a = 10;
    let b = 0;

    let result = match b {
        0 => None,
        _ => Some(a / b),
    };

    match result {
        Some(r) => println!("Result: {}", r),
        None => println!("Division by zero error")
    }
}

